// 2.8   | 2022-06-07 | raj |  STRY0119248 - Draft Tasks- No Email Notifications (with one exception)
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
//	if (!new global.StateFlow().validateMandatory(current, previous, 'x_153465_discovert_route_task_instance')) 
//		current.setAbortAction(true);
	if (current.state.changes()){
		//new global.StateFlow().addWorkNotes(current, previous, 'x_153465_discovert_route_task_instance');
		current.work_notes = new Task_Business_Rules().stateChangeWorkNote(current, previous);
		//STRY0119248 - don't send in previous state was draft state
		if(previous.state != -6){
			gs.eventQueue("x_153465_discovert.TaskChanged",current,'','');			
		}
	}
})(current, previous);
